UPDATE bot_daily_parlays SET outcome = 'void', settled_at = now(), lesson_learned = 'Voided: L3 gate bypass due to NULL l3_avg data' WHERE outcome IS NULL AND parlay_date = CURRENT_DATE AND EXISTS ( SELECT 1 FROM jsonb_array_elements(legs) AS leg WHERE (leg->>'player_name' ILIKE '%mobley%' AND leg->>'prop_type' ILIKE '%assist%') OR (leg->>'player_name' ILIKE '%mitchell%' AND (leg->>'line')::numeric < 20) );